INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (155, "ヒヨリ", "人助けが大好き！　前向き格闘娘", "人助け、応援", "A", 27, 2, "獣人族", "東山奈央", "トゥインクルウィッシュ", 8, 0, 44, 16, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 100101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (158, "ユイ", "戦闘のサポートが得意な、心優しい少女", "料理、人間観察", "O", 5, 2, "ヒューマン", "種田梨沙", "トゥインクルウィッシュ", 4, 0, 47, 17, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 100201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (163, "レイ", "クールで何事にも真っ直ぐな剣士", "読書、乗馬、お茶", "B", 12, 2, "魔族", "早見沙織", "トゥインクルウィッシュ", 1, 0, 46, 18, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 100301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (128, "ミソギ", "探検好きのイタズラっ子", "いたずら、探検", "O", 10, 5, "ヒューマン", "諸星すみれ", "リトルリリカル", 8, 0, 27, 9, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 100401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (146, "マツリ", "ヒーローに憧れる騎士見習いの少女", "ヒーローごっこ", "O", 25, 8, "獣人族", "下田麻美", "王宮騎士団（NIGHTMARE）", 11, 0, 40, 12, "？？？", 100501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (150, "アカリ", "甘え上手なみんなの人気者", "サックス", "O", 22, 7, "魔族", "浅倉杏美", "悪魔偽王国軍（ディアボロス）", 11, 0, 42, 13, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 100601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (130, "ミヤコ", "プリン大好きゴースト娘", "プリンを食べること", "B", 23, 7, "魔族", "雨宮天", "悪魔偽王国軍（ディアボロス）", 1, 0, 32, 14, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 100701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (150, "ユキ", "ボクは誰よりも美しい", "鏡で自分を見ること", "AB", 10, 15, "エルフ", "大空直美", "ヴァイスフリューゲル　ランドソル支部", 10, 0, 40, 14, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 100801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (159, "アンナ", "前世を信じる中二病患者、「疾風の冥姫」", "小説執筆", "A", 5, 13, "魔族", "髙野麻美", "トワイライトキャラバン", 7, 0, 45, 17, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 100901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (155, "マホ", "マホマホ王国のプリンセス", "空想、ぬいぐるみ集め", "O", 22, 10, "獣人族", "内田真礼", "自警団（カォン）", 9, 0, 42, 16, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 101001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (156, "リノ", "人懐っこくてマシンガントークな妹系少女", "お裁縫", "A", 25, 3, "ヒューマン", "阿澄佳奈", "ラビリンス", 8, 0, 44, 15, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 101101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (156, "ハツネ", "みんなのために超能力を使う眠り姫", "妹と遊ぶこと、二度寝、昼寝、早寝", "A", 24, 6, "エルフ", "大橋彩香", "フォレスティエ", 12, 0, 46, 17, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 101201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (166, "ナナカ", "オタク全開な魔法少女", "読書、魔法", "O", 21, 13, "魔族", "佳村はるか", "トワイライトキャラバン", 8, 0, 55, 18, "", 101301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (152, "カスミ", "頭脳明晰な美少女名探偵", "読書、推理", "AB", 3, 10, "獣人族", "水瀬いのり", "自警団（カォン）", 11, 0, 41, 15, "test", 101401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (165, "ミサト", "母性溢れる優しいみんなの「ミサト先生」", "絵本作り", "O", 5, 6, "エルフ", "國府田マリ子", "フォレスティエ", 9, 0, 54, 21, "test", 101501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (167, "スズナ", "天真爛漫で人気者のカリスマモデル", "ファッション", "O", 10, 14, "魔族", "上坂すみれ", "ルーセント学院", 4, 0, 48, 17, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 101601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (158, "カオリ", "いつでも「なんくるないさ～」な天然娘", "踊り、空手", "A", 7, 10, "獣人族", "高森奈津美", "自警団（カォン）", 7, 0, 53, 17, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 101701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (162, "イオ", "多くの男性を魅了する無垢な女教師", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "B", 14, 14, "魔族", "伊藤静", "ルーセント学院", 8, 0, 52, 23, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 101801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117, "ミミ", "お歌もにんじんも、ウサギさんも大好き♪", "かわいいもの集め", "O", 3, 5, "獣人族", "日高里菜", "リトルリリカル", 4, 0, 21, 10, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 102001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (150, "クルミ", "泣き虫で臆病な守ってあげたい女の子", "観劇、おままごと", "B", 9, 9, "ヒューマン", "植田佳奈", "サレンディア救護院", 6, 0, 40, 12, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 102101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (150, "ヨリ", "人見知りであまのじゃくな女の子", "ゲーム全般", "O", 22, 7, "魔族", "原紗友里", "悪魔偽王国軍（ディアボロス）", 11, 0, 40, 13, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 102201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (148, "アヤネ", "ぷうきちといつも一緒！", "屋内でできる遊び", "B", 10, 9, "ヒューマン", "芹澤優", "サレンディア救護院", 5, 0, 38, 14, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 102301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (154, "スズメ", "お嬢さまのためにがんばるドジっ娘メイド", "ご奉仕", "O", 12, 9, "ヒューマン", "悠木碧", "サレンディア救護院", 12, 0, 43, 15, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 102501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (144, "リン", "遊びと睡眠が何より大事なぐうたら娘", "あんパン", "B", 1, 11, "獣人族", "小岩井ことり", "牧場（エリザベスパーク）", 1, 0, 42, 17, "test", 102601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (154, "エリコ", "運命の相手に一途すぎる乙女", "実験、裁縫、料理", "B", 30, 13, "魔族", "橋本ちなみ", "トワイライトキャラバン", 7, 0, 43, 16, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 102701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (156, "サレン", "救護院を経営する優しい庶民派お嬢様", "経営、お茶会", "A", 4, 9, "エルフ", "堀江由衣", "サレンディア救護院", 10, 0, 43, 17, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 102801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (157, "ノゾミ", "歌って踊れる大人気アイドル", "舞台鑑賞、ダンス", "B", 24, 4, "ヒューマン", "日笠陽子", "カルミナ", 1, 0, 40, 17, "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", 102901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (163, "ニノン", "トーゴクの神秘、オシエテクダサイ！", "忍法開発", "O", 31, 15, "ヒューマン", "佐藤聡美", "ヴァイスフリューゲル　ランドソル支部", 8, 0, 51, 16, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 103001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (157, "シノブ", "占いが得意な霊能少女", "占い", "AB", 22, 7, "魔族", "大坪由佳", "悪魔偽王国軍（ディアボロス）", 12, 0, 42, 18, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 103101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (157, "アキノ", "一人前の商人を目指すパワフルお嬢様", "慈善事業", "AB", 12, 12, "ヒューマン", "松嵜麗", "メルクリウス財団", 3, 0, 45, 18, "この私とともにいる限り、\nお金に不自由はさせませんわ！", 103201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (142, "マヒル", "みんなを笑顔にするお笑い牧場主", "漫才", "B", 3, 11, "ヒューマン", "新田恵海", "牧場（エリザベスパーク）", 3, 0, 35, 20, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 103301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (164, "ユカリ", "純情でほっとけない大人の女性", "ウインドーショッピング", "A", 16, 12, "エルフ", "今井麻美", "メルクリウス財団", 3, 0, 55, 22, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 103401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (118, "キョウカ", "礼儀正しくしっかり者のちびっ子優等生", "お勉強", "A", 2, 5, "エルフ", "小倉唯", "リトルリリカル", 2, 0, 21, 8, "test", 103601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (149, "トモ", "義理堅くてからかい好きな剣術少女", "剣術、年長者をからかう", "A", 11, 8, "ヒューマン", "茅原実里", "王宮騎士団（NIGHTMARE）", 8, 0, 43, 13, "test", 103701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (153, "シオリ", "読書が趣味の病弱少女", "読書、お散歩", "A", 3, 11, "獣人族", "小清水亜美", "牧場（エリザベスパーク）", 11, 0, 40, 14, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 103801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (158, "アオイ", "「友達」に憧れる、エルフの森の女の子", "友達作りのイメトレ", "AB", 6, 6, "エルフ", "花澤香菜", "フォレスティエ", 6, 0, 44, 13, "友達ができるその日まで…\nBB団で\nトレーニングですっ！", 104001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (163, "チカ", "人々を守るために歌う、唱喚士の少女", "各種楽器", "O", 3, 4, "ヒューマン", "福原綾香", "カルミナ", 6, 0, 46, 17, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 104201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (168, "マコト", "男勝りで情に厚いワイルド娘", "お菓子作り", "O", 9, 10, "獣人族", "小松未可子", "自警団（カォン）", 8, 0, 54, 17, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 104301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (172, "イリヤ", "かつては夜を支配した最強の吸血鬼", "世界征服", "A", 5, 7, "魔族", "丹下桜", "悪魔偽王国軍（ディアボロス）", 5, 0, 50, "??", "test", 104401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (157, "クウカ", "妄想大好き！　ほんとは照れ屋な女の子", "小説を読むこと", "AB", 19, 15, "ヒューマン", "長妻樹里", "ヴァイスフリューゲル　ランドソル支部", 11, 0, 49, 18, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 104501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (158, "タマキ", "弱きを助け強きをくじく猫娘", "猫とたわむれること", "AB", 1, 12, "獣人族", "沼倉愛美", "メルクリウス財団", 3, 0, 48, 19, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 104601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (171, "ジュン", "素顔を見せない冷静沈着な女性騎士", "格闘技、湯浴み", "A", 25, 8, "ヒューマン", "川澄綾子", "王宮騎士団（NIGHTMARE）", 10, 0, 50, 25, "？？？", 104701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (163, "ミフユ", "仕事も私事も効率優先な傭兵少女", "傭兵などのアルバイト", "O", 11, 12, "ヒューマン", "田所あずさ", "メルクリウス財団", 11, 0, 49, 20, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 104801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (168, "シズル", "お姉ちゃんがお世話してあげるからねっ！", "家事全般", "O", 24, 3, "ヒューマン", "生天目仁美", "ラビリンス", 10, 0, 54, 18, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 104901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (120, "ミサキ", "ちょっとおませな恋に恋する女の子", "ファッション誌鑑賞、コスメ集め", "A", 3, 14, "魔族", "久野美咲", "ルーセント学院", 1, 0, 22, 11, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 105001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (166, "ミツキ", "実験が趣味の危険な科学者", "研究、実験", "A", 7, 13, "ヒューマン", "三石琴乃", "トワイライトキャラバン", 3, 0, 53, 27, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 105101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (150, "リマ", "乙女チックなもふもふアニマル", "毛繕い、お喋り", "A", 14, 11, "獣人族", "徳井青空", "牧場（エリザベスパーク）", 3, 0, 100, 17, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 105201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (140, "モニカ", "見た目も中身もお子ちゃまな異国の軍人", "お菓子屋通い", "A", 28, 15, "ヒューマン", "辻あゆみ", "ヴァイスフリューゲル　ランドソル支部", 7, 0, 33, 17, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 105301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (153, "ツムギ", "ファッション大好きなキュートガール", "裁縫", "AB", 7, 4, "ヒューマン", "木戸衣吹", "カルミナ", 9, 0, 45, 14, "test", 105401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (155, "アユミ", "どこまでも一途に慕う、純情乙女", "観察", "O", 7, 15, "エルフ", "大関英里", "ヴァイスフリューゲル　ランドソル支部", 4, 0, 43, 16, "test", 105501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (167, "ルカ", "人情味溢れる粋でいなせな「姉御」", "釣り", "B", 11, 13, "ヒューマン", "佐藤利奈", "トワイライトキャラバン", 7, 0, 54, 25, "test", 105601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (156, "ジータ", "空への冒険を夢見る騎空士の少女", "冒険、おしゃべり", "O", 10, "", "ヒューマン", "金元寿子", "？？？", 3, 0, 45, 17, "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", 105701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (156, "ペコリーヌ", "いつも元気な腹ペコ少女", "食べ歩き、料理", "O", 31, 1, "ヒューマン", "M・A・O", "美食殿", 3, 0, 46, 17, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 105801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (140, "コッコロ", "主を慕う、小さなガイド役", "瞑想、動植物の飼育", "B", 11, 1, "エルフ", "伊藤美来", "美食殿", 5, 0, 35, 11, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 105901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (152, "キャル", "行き倒れの謎のネコミミ魔法使い", "猫と遊ぶ", "A", 2, 1, "獣人族", "立花理香", "美食殿", 9, 0, 39, 14, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 106001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (148, "ムイミ", "さまよえる謎の少女", "冒険、思い出話", "O", 11, "", "ヒューマン", "潘めぐみ", "？？？", 8, 0, 40, 16, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", 106101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (155, "アリサ", "森番を目指すエルフの少女", "キレイな葉っぱを集めること", "O", 17, "", "エルフ", "優木かな", "？？？", 6, 0, 42, 15, "", 106301);
