INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (168, "ホマレ", "妖しい微笑で全てを見透かす臥竜の頭領", "絵画、読書", "O", 17, 17, "ドラゴン族", "大西沙織", "ドラゴンズネスト", 4, 0, "???", 25, "", 106701);
