INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (165, "クリスティーナ", "傍若無人な王宮騎士団副団長", "強敵との闘争", "O", 7, 8, "ヒューマン", "たかはし智秋", "王宮騎士団（NIGHTMARE）", 2, 0, "??", 27, "", 107101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (156, "ペコリーヌ（サマー）", "いつも元気な腹ペコ少女", "食べ歩き、料理", "O", 31, 1, "ヒューマン", "M・A・O", "美食殿", 3, 0, 46, 17, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 107501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (140, "コッコロ（サマー）", "主を慕う、小さなガイド役", "瞑想、動植物の飼育", "B", 11, 1, "エルフ", "伊藤美来", "美食殿", 5, 0, 35, 11, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 107601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (154, "スズメ（サマー）", "お嬢さまのためにがんばるドジっ娘メイド", "ご奉仕", "O", 12, 9, "ヒューマン", "悠木碧", "サレンディア救護院", 12, 0, 43, 15, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 107701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (152, "キャル（サマー）", "行き倒れの謎のネコミミ魔法使い", "猫と遊ぶ", "A", 2, 1, "獣人族", "立花理香", "美食殿", 9, 0, 39, 14, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 107801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (158, "タマキ（サマー）", "弱きを助け強きをくじく猫娘", "猫とたわむれること", "AB", 1, 12, "獣人族", "沼倉愛美", "メルクリウス財団", 3, 0, 48, 19, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 107901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (163, "ミフユ（サマー）", "仕事も私事も効率優先な傭兵少女", "傭兵などのアルバイト", "O", 11, 12, "ヒューマン", "田所あずさ", "メルクリウス財団", 11, 0, 49, 20, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 108001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (157, "シノブ（ハロウィン）", "占いが得意な霊能少女", "占い", "AB", 22, 7, "魔族", "大坪由佳", "悪魔偽王国軍（ディアボロス）", 12, 0, 42, 18, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 108101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (130, "ミヤコ（ハロウィン）", "プリン大好きゴースト娘", "プリンを食べること", "B", 23, 7, "魔族", "雨宮天", "悪魔偽王国軍（ディアボロス）", 1, 0, 32, 14, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 108201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (120, "ミサキ（ハロウィン）", "ちょっとおませな恋に恋する女の子", "ファッション誌鑑賞、コスメ集め", "A", 3, 14, "魔族", "久野美咲", "ルーセント学院", 1, 0, 22, 11, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 108301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (163, "チカ（クリスマス）", "人々を守るために歌う、唱喚士の少女", "各種楽器", "O", 3, 4, "ヒューマン", "福原綾香", "カルミナ", 6, 0, 46, 17, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 108401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (150, "クルミ（クリスマス）", "泣き虫で臆病な守ってあげたい女の子", "観劇、おままごと", "B", 9, 9, "ヒューマン", "植田佳奈", "サレンディア救護院", 6, 0, 40, 12, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 108501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (148, "アヤネ（クリスマス）", "ぷうきちといつも一緒！", "屋内でできる遊び", "B", 10, 9, "ヒューマン", "芹澤優", "サレンディア救護院", 5, 0, 38, 14, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 108601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (155, "ヒヨリ（ニューイヤー）", "人助けが大好き！　前向き格闘娘", "人助け、応援", "A", 27, 2, "獣人族", "東山奈央", "トゥインクルウィッシュ", 8, 0, 44, 16, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 108701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (158, "ユイ（ニューイヤー）", "戦闘のサポートが得意な、心優しい少女", "料理、人間観察", "O", 5, 2, "ヒューマン", "種田梨沙", "トゥインクルウィッシュ", 4, 0, 47, 17, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 108801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (163, "レイ（ニューイヤー）", "クールで何事にも真っ直ぐな剣士", "読書、乗馬、お茶", "B", 12, 2, "魔族", "早見沙織", "トゥインクルウィッシュ", 1, 0, 46, 18, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 108901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (154, "エリコ（バレンタイン）", "運命の相手に一途すぎる乙女", "実験、裁縫、料理", "B", 30, 13, "魔族", "橋本ちなみ", "トワイライトキャラバン", 7, 0, 43, 16, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 109001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (168, "シズル（バレンタイン）", "お姉ちゃんがお世話してあげるからねっ！", "家事全般", "O", 24, 3, "ヒューマン", "生天目仁美", "ラビリンス", 10, 0, 54, 18, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 109101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (156, "アン", "英霊と契約を結んだマナリアの天才王女", "読書", "AB", 1, "", "ヒューマン", "日笠陽子", "？？？", 12, 0, 55, 17, "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", 109201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (144, "ルゥ", "マナリア魔法学院の新入生", "食べること、眠ること", "O", 4, "", "ヒューマン", "こやまきみこ", "？？？", 2, 0, 45, 16, "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", 109301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (167, "グレア", "人を超越した力を有す心優しい竜姫", "ピアノ", "B", 3, "", "半人半竜", "福原綾香", "？？？", 11, 0, 67, 17, "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", 109401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (157, "クウカ（オーエド）", "妄想大好き！　ほんとは照れ屋な女の子", "小説を読むこと", "AB", 19, 15, "ヒューマン", "長妻樹里", "ヴァイスフリューゲル　ランドソル支部", 11, 0, 49, 18, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 109501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (163, "ニノン（オーエド）", "トーゴクの神秘、オシエテクダサイ！", "忍法開発", "O", 31, 15, "ヒューマン", "佐藤聡美", "ヴァイスフリューゲル　ランドソル支部", 8, 0, 51, 16, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 109601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (154, "レム", "鬼がかりの万能妹メイド", "演劇鑑賞、詩文", "?", 2, "", "鬼族", "水瀬いのり", "？？？", 2, 0, "??", 17, "", 109701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (154, "ラム", "毒舌系鬼姉メイド", "読書", "?", 2, "", "鬼族", "村川梨衣", "？？？", 2, 0, "??", 17, "", 109801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (164, "エミリア", "銀髪のおっとりハーフエルフ", "パックの毛繕い、勉強", "?", 23, "", "ハーフエルフ", "高橋李依", "？？？", 9, 0, "??", "??", "", 109901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (167, "スズナ（サマー）", "天真爛漫で人気者のカリスマモデル", "ファッション", "O", 10, 14, "魔族", "上坂すみれ", "ルーセント学院", 4, 0, 48, 17, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 110001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (162, "イオ（サマー）", "多くの男性を魅了する無垢な女教師", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "B", 14, 14, "魔族", "伊藤静", "ルーセント学院", 8, 0, 52, 23, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 110101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (120, "ミサキ（サマー）", "ちょっとおませな恋に恋する女の子", "ファッション誌鑑賞、コスメ集め", "A", 3, 14, "魔族", "久野美咲", "ルーセント学院", 1, 0, 22, 11, "", 110201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (156, "サレン（サマー）", "救護院を経営する優しい庶民派お嬢様", "経営、お茶会", "A", 4, 9, "エルフ", "堀江由衣", "サレンディア救護院", 10, 0, 43, 17, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 110301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (168, "マコト（サマー）", "男勝りで情に厚いワイルド娘", "お菓子作り", "O", 9, 10, "獣人族", "小松未可子", "自警団（カォン）", 8, 0, 54, 17, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 110401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (158, "カオリ（サマー）", "いつでも「なんくるないさ～」な天然娘", "踊り、空手", "A", 7, 10, "獣人族", "高森奈津美", "自警団（カォン）", 7, 0, 53, 17, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 110501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (155, "マホ（サマー）", "マホマホ王国のプリンセス", "空想、ぬいぐるみ集め", "O", 22, 10, "獣人族", "内田真礼", "自警団（カォン）", 9, 0, 42, 16, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 110601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (158, "アオイ（編入生）", "「友達」に憧れる、エルフの森の女の子", "友達作りのイメトレ", "AB", 6, 6, "エルフ", "花澤香菜", "フォレスティエ", 6, 0, 44, 13, "", 110701);
