INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (156, "チエル", "自由奔放ナチュラル無礼な現代っ子", "ダンス、カラオケ", "O", 15, 16, "ヒューマン", "佐倉綾音", "聖テレサ女学院（なかよし部）", 9, 0, 46, 16, "", 110901);
