INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (118, "キョウカ（ハロウィン）", "礼儀正しくしっかり者のちびっ子優等生", "お勉強", "A", 2, 5, "エルフ", "小倉唯", "リトルリリカル", 2, 0, 21, 8, "", 111101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (128, "ミソギ（ハロウィン）", "探検好きのイタズラっ子", "いたずら、探検", "O", 10, 5, "ヒューマン", "諸星すみれ", "リトルリリカル", 8, 0, 27, 9, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 111201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117, "ミミ（ハロウィン）", "お歌もにんじんも、ウサギさんも大好き♪", "かわいいもの集め", "O", 3, 5, "獣人族", "日高里菜", "リトルリリカル", 4, 0, 21, 10, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 111301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (142, "ルナ", "おともだちを探す死霊術師の少女", "「おともだち」を探すこと", "?", 8, "", "ヒューマン", "小倉唯", "？？？", 1, 0, 28, "??", "", 111401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (165, "クリスティーナ（クリスマス）", "傍若無人な王宮騎士団副団長", "強敵との闘争", "O", 7, 8, "ヒューマン", "たかはし智秋", "王宮騎士団（NIGHTMARE）", 2, 0, "??", 27, "", 111501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (157, "ノゾミ（クリスマス）", "歌って踊れる大人気アイドル", "舞台鑑賞、ダンス", "B", 24, 4, "ヒューマン", "日笠陽子", "カルミナ", 1, 0, 40, 17, "", 111601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (172, "イリヤ（クリスマス）", "かつては夜を支配した最強の吸血鬼", "世界征服", "A", 5, 7, "魔族", "丹下桜", "悪魔偽王国軍（ディアボロス）", 5, 0, 50, "??", "", 111701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (156, "ぺコリーヌ（ニューイヤー）", "いつも元気な腹ペコ少女", "食べ歩き、料理", "O", 31, 1, "ヒューマン", "M・A・O", "美食殿", 3, 0, 46, 17, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 111801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (140, "コッコロ（ニューイヤー）", "主を慕う、小さなガイド役", "瞑想、動植物の飼育", "B", 11, 1, "エルフ", "伊藤美来", "美食殿", 5, 0, 35, 11, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 111901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (152, "キャル（ニューイヤー）", "行き倒れの謎のネコミミ魔法使い", "猫と遊ぶ", "A", 2, 1, "獣人族", "立花理香", "美食殿", 9, 0, 39, 14, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 112001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (154, "スズメ（ニューイヤー）", "お嬢さまのためにがんばるドジっ娘メイド", "ご奉仕", "O", 12, 9, "ヒューマン", "悠木碧", "サレンディア救護院", 12, 0, 43, 15, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 112101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (152, "カスミ（マジカル）", "頭脳明晰な美少女名探偵", "読書、推理", "AB", 3, 10, "獣人族", "水瀬いのり", "自警団（カォン）", 11, 0, 41, 15, "", 112201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (153, "シオリ（マジカル）", "読書が趣味の病弱少女", "読書、お散歩", "A", 3, 11, "獣人族", "小清水亜美", "牧場（エリザベスパーク）", 11, 0, 40, 14, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 112301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (159, "ウヅキ（デレマス）", "弾ける笑顔！　アイドルを夢見る女の子", "友達と長話", "O", 24, 100, "ヒューマン", "大橋彩香", "ニュージェネレーションズ", 4, 0, 45, 17, "", 112401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (165, "リン（デレマス）", "クールビューティーな「蒼の剣士」", "犬の散歩", "B", 10, 100, "ヒューマン", "福原綾香", "ニュージェネレーションズ", 8, 0, 44, 15, "", 112501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (161, "ミオ（デレマス）", "スーパースターを目指す元気娘☆☆★", "ショッピング", "B", 1, 100, "ヒューマン", "原紗友里", "ニュージェネレーションズ", 12, 0, 46, 15, "", 112601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (144, "リン（レンジャー）", "遊びと睡眠が何より大事なぐうたら娘", "あんパン", "B", 1, 11, "獣人族", "小岩井ことり", "牧場（エリザベスパーク）", 1, 0, 42, 17, "", 112701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (142, "マヒル（レンジャー）", "みんなを笑顔にするお笑い牧場主", "漫才", "B", 3, 11, "ヒューマン", "新田恵海", "牧場（エリザベスパーク）", 3, 0, 35, 20, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 112801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (156, "リノ（ワンダー）", "人懐っこくてマシンガントークな妹系少女", "お裁縫", "A", 25, 3, "ヒューマン", "阿澄佳奈", "ラビリンス", 8, 0, 44, 15, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 112901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (155, "アユミ（ワンダー）", "どこまでも一途に慕う、純情乙女", "観察", "O", 7, 15, "エルフ", "大関英里", "ヴァイスフリューゲル　ランドソル支部", 4, 0, 43, 16, "", 113001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (167, "ルカ（サマー）", "人情味溢れる粋でいなせな「姉御」", "釣り", "B", 11, 13, "ヒューマン", "佐藤利奈", "トワイライトキャラバン", 7, 0, 54, 25, "", 113101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (159, "アンナ（サマー）", "前世を信じる中二病患者、「疾風の冥姫」", "小説執筆", "A", 5, 13, "魔族", "髙野麻美", "トワイライトキャラバン", 7, 0, 45, 17, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 113201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (166, "ナナカ（サマー）", "オタク全開な魔法少女", "読書、魔法", "O", 21, 13, "魔族", "佳村はるか", "トワイライトキャラバン", 8, 0, 55, 18, "", 113301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (156, "ハツネ（サマー）", "みんなのために超能力を使う眠り姫", "妹と遊ぶこと、二度寝、昼寝、早寝", "A", 24, 6, "エルフ", "大橋彩香", "フォレスティエ", 12, 0, 46, 17, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 113401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (165, "ミサト（サマー）", "母性溢れる優しいみんなの「ミサト先生」", "絵本作り", "O", 5, 6, "エルフ", "國府田マリ子", "フォレスティエ", 9, 0, 54, 21, "", 113501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (171, "ジュン（サマー）", "素顔を見せない冷静沈着な女性騎士", "格闘技、湯浴み", "A", 25, 8, "ヒューマン", "川澄綾子", "王宮騎士団（NIGHTMARE）", 10, 0, 50, 25, "", 113601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (150, "アカリ（エンジェル）", "甘え上手なみんなの人気者", "サックス", "O", 22, 7, "魔族", "浅倉杏美", "悪魔偽王国軍（ディアボロス）", 11, 0, 42, 13, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 113701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (150, "ヨリ（エンジェル）", "人見知りであまのじゃくな女の子", "ゲーム全般", "O", 22, 7, "魔族", "原紗友里", "悪魔偽王国軍（ディアボロス）", 11, 0, 40, 13, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 113801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (153, "ツムギ（ハロウィン）", "ファッション大好きなキュートガール", "裁縫", "AB", 7, 4, "ヒューマン", "木戸衣吹", "カルミナ", 9, 0, 45, 14, "", 113901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (163, "レイ（ハロウィン）", "クールで何事にも真っ直ぐな剣士", "読書、乗馬、お茶", "B", 12, 2, "魔族", "早見沙織", "トゥインクルウィッシュ", 1, 0, 46, 18, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 114001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (146, "マツリ（ハロウィン）", "ヒーローに憧れる騎士見習いの少女", "ヒーローごっこ", "O", 25, 8, "獣人族", "下田麻美", "王宮騎士団（NIGHTMARE）", 11, 0, 40, 12, "", 114101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (140, "モニカ（マジカル）", "見た目も中身もお子ちゃまな異国の軍人", "お菓子屋通い", "A", 28, 15, "ヒューマン", "辻あゆみ", "ヴァイスフリューゲル　ランドソル支部", 7, 0, 33, 17, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 114201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (149, "トモ（マジカル）", "義理堅くてからかい好きな剣術少女", "剣術、年長者をからかう", "A", 11, 8, "ヒューマン", "茅原実里", "王宮騎士団（NIGHTMARE）", 8, 0, 43, 13, "", 114301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (157, "アキノ（クリスマス）", "一人前の商人を目指すパワフルお嬢様", "慈善事業", "AB", 12, 12, "ヒューマン", "松嵜麗", "メルクリウス財団", 3, 0, 45, 18, "この私とともにいる限り、\nお金に不自由はさせませんわ！", 114401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (156, "サレン（クリスマス）", "救護院を経営する優しい庶民派お嬢様", "経営、お茶会", "A", 4, 9, "エルフ", "堀江由衣", "サレンディア救護院", 10, 0, 43, 17, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 114501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (164, "ユカリ（クリスマス）", "純情でほっとけない大人の女性", "ウインドーショッピング", "A", 16, 12, "エルフ", "今井麻美", "メルクリウス財団", 3, 0, 55, 22, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 114601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (148, "ムイミ（ニューイヤー）", "さまよえる謎の少女", "冒険、思い出話", "O", 11, "", "ヒューマン", "潘めぐみ", "？？？", 8, 0, 40, 16, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", 114701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (149, "ネネカ（ニューイヤー）", "研究所に隠れ住む物静かなお姉さん", "物真似、芸術鑑賞", "O", 24, "", "エルフ", "井口裕香", "？？？", 3, 0, "??", 24, "", 115001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (140, "コッコロ（儀装束）", "主を慕う、小さなガイド役", "瞑想、動植物の飼育", "B", 11, 1, "エルフ", "伊藤美来", "美食殿", 5, 0, 35, 11, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 115501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (158, "ユイ（儀装束）", "戦闘のサポートが得意な、心優しい少女", "料理、人間観察", "O", 5, 2, "ヒューマン", "種田梨沙", "トゥインクルウィッシュ", 4, 0, 47, 17, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 115601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (152, "カスミ（サマー）", "頭脳明晰な美少女名探偵", "読書、推理", "AB", 3, 10, "獣人族", "水瀬いのり", "自警団（カォン）", 11, 0, 41, 15, "", 115701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (150, "リマ（シンデレラ）", "乙女チックなもふもふアニマル", "毛繕い、お喋り", "A", 14, 11, "獣人族", "徳井青空", "牧場（エリザベスパーク）", 3, 0, 100, 17, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 115801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (168, "マコト（シンデレラ）", "男勝りで情に厚いワイルド娘", "お菓子作り", "O", 9, 10, "獣人族", "小松未可子", "自警団（カォン）", 8, 0, 54, 17, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 115901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (155, "マホ（シンデレラ）", "マホマホ王国のプリンセス", "空想、ぬいぐるみ集め", "O", 22, 10, "獣人族", "内田真礼", "自警団（カォン）", 9, 0, 42, 16, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 116001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (154, "クロエ（聖学祭）", "ダウンタウン育ちのダウナー系エルフ", "ダーツ", "O", 7, 16, "エルフ", "種﨑敦美", "聖テレサ女学院（なかよし部）", 8, 0, 42, 17, "", 116201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (156, "チエル（聖学祭）", "自由奔放ナチュラル無礼な現代っ子", "ダンス、カラオケ", "O", 15, 16, "ヒューマン", "佐倉綾音", "聖テレサ女学院（なかよし部）", 9, 0, 46, 16, "", 116301);
