INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (145, "イノリ（タイムトラベル）", "口が達者なヘタレドラゴン", "ゲーム", "AB", 29, 17, "ドラゴン族", "藤田茜", "ドラゴンズネスト", 9, 0, "???", 13, "", 116501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (156, "カヤ（タイムトラベル）", "拳で語る喧嘩屋ドラゴン少女", "格闘技", "B", 25, 17, "ドラゴン族", "小市眞琴", "ドラゴンズネスト", 6, 0, "???", 16, "", 116601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (158, "アオイ（作業服）", "「友達」に憧れる、エルフの森の女の子", "友達作りのイメトレ", "AB", 6, 6, "エルフ", "花澤香菜", "フォレスティエ", 6, 0, 44, 13, "", 116701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (158, "タマキ（作業服）", "弱きを助け強きをくじく猫娘", "猫とたわむれること", "AB", 1, 12, "獣人族", "沼倉愛美", "メルクリウス財団", 3, 0, 48, 19, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 116801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (163, "ミフユ（作業服）", "仕事も私事も効率優先な傭兵少女", "傭兵などのアルバイト", "O", 11, 12, "ヒューマン", "田所あずさ", "メルクリウス財団", 11, 0, 49, 20, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 116901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (154, "エリコ（サマー）", "運命の相手に一途すぎる乙女", "実験、裁縫、料理", "B", 30, 13, "魔族", "橋本ちなみ", "トワイライトキャラバン", 7, 0, 43, 16, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 117001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (168, "シズル（サマー）", "お姉ちゃんがお世話してあげるからねっ！", "家事全般", "O", 24, 3, "ヒューマン", "生天目仁美", "ラビリンス", 10, 0, 54, 18, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 117101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (157, "ノゾミ（サマー）", "歌って踊れる大人気アイドル", "舞台鑑賞、ダンス", "B", 24, 4, "ヒューマン", "日笠陽子", "カルミナ", 1, 0, 40, 17, "", 117201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (163, "チカ（サマー）", "人々を守るために歌う、唱喚士の少女", "各種楽器", "O", 3, 4, "ヒューマン", "福原綾香", "カルミナ", 6, 0, 46, 17, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 117301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (153, "ツムギ（サマー）", "ファッション大好きなキュートガール", "裁縫", "AB", 7, 4, "ヒューマン", "木戸衣吹", "カルミナ", 9, 0, 45, 14, "", 117401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (166, "ミツキ（オーエド）", "実験が趣味の危険な科学者", "研究、実験", "A", 7, 13, "ヒューマン", "三石琴乃", "トワイライトキャラバン", 3, 0, 53, 27, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 117501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (150, "ユキ（オーエド）", "ボクは誰よりも美しい", "鏡で自分を見ること", "AB", 10, 15, "エルフ", "大空直美", "ヴァイスフリューゲル　ランドソル支部", 10, 0, 40, 14, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 117601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (158, "カオリ（ハロウィン）", "いつでも「なんくるないさ～」な天然娘", "踊り、空手", "A", 7, 10, "獣人族", "高森奈津美", "自警団（カォン）", 7, 0, 53, 17, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 117701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (163, "ニノン（ハロウィン）", "トーゴクの神秘、オシエテクダサイ！", "忍法開発", "O", 31, 15, "ヒューマン", "佐藤聡美", "ヴァイスフリューゲル　ランドソル支部", 8, 0, 51, 16, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 117801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (167, "スズナ（ハロウィン）", "天真爛漫で人気者のカリスマモデル", "ファッション", "O", 10, 14, "魔族", "上坂すみれ", "ルーセント学院", 4, 0, 48, 17, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 117901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (160, "クレジッタ", "忠義に目覚めた女商人", "お金を数えること、悪だくみ", "A", 19, 18, "ヒューマン", "Lynn", "リッチモンド商工会", 9, 0, 57, 26, "", 118001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (165, "ランファ", "静寂を求め歌う陰気少女", "歌、読書、詩を書くこと", "O", 28, 19, "魔族", "原田彩楓", "レイジ・レギオン", 12, 0, 53, 20, "", 118101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (159, "ミソラ", "明朗快活、なれど破滅に流るる溌溂少女", "特に無し", "A", 2, 19, "ヒューマン", "鬼頭明里", "レイジ・レギオン", 7, 0, "??", 16, "", 118201);
