INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (162, "イオ（ノワール）", "多くの男性を魅了する無垢な女教師", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "B", 14, 14, "魔族", "伊藤静", "ルーセント学院", 8, 0, 52, 23, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 119001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (157, "クウカ（ノワール）", "妄想大好き！　ほんとは照れ屋な女の子", "小説を読むこと", "AB", 19, 15, "ヒューマン", "長妻樹里", "ヴァイスフリューゲル　ランドソル支部", 11, 0, 49, 18, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 119101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (142, "マヒル（クリスマス）", "みんなを笑顔にするお笑い牧場主", "漫才", "B", 3, 11, "ヒューマン", "新田恵海", "牧場（エリザベスパーク）", 3, 0, 35, 20, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 119201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (156, "リノ（クリスマス）", "人懐っこくてマシンガントークな妹系少女", "お裁縫", "A", 25, 3, "ヒューマン", "阿澄佳奈", "ラビリンス", 8, 0, 44, 15, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 119301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (130, "ミヤコ（クリスマス）", "プリン大好きゴースト娘", "プリンを食べること", "B", 23, 7, "魔族", "雨宮天", "悪魔偽王国軍（ディアボロス）", 1, 0, 32, 14, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 119901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (168, "シズル（ノワール）", "お姉ちゃんがお世話してあげるからねっ！", "家事全般", "O", 24, 3, "ヒューマン", "生天目仁美", "ラビリンス", 10, 0, 54, 18, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 120001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (147, "シェフィ（ニューイヤー）", "記憶喪失のドラゴン娘", "読書、ストレッチ", "B", 14, 1, "ドラゴン族", "近藤玲奈", "美食殿", 12, 0, "???", 14, "", 120701);
