INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (172, "イリヤ（ニューイヤー）", "かつては夜を支配した最強の吸血鬼", "世界征服", "A", 5, 7, "魔族", "丹下桜", "悪魔偽王国軍（ディアボロス）", 5, 0, 50, "??", "", 120901);
