INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (152, "キャル（オーバーロード）", "行き倒れの謎のネコミミ魔法使い", "猫と遊ぶ", "A", 2, 1, "獣人族", "立花理香", "美食殿", 9, 0, 39, 14, "", 121101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (160, "ラビリスタ（オーバーロード）", "秘密結社ラビリンスの『迷宮女王』", "人間観察", "AB", 25, 3, "ヒューマン", "沢城みゆき", "ラビリンス", 7, 0, "??", 25, "", 121201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (150, "クルミ（ステージ）", "泣き虫で臆病な守ってあげたい女の子", "観劇、おままごと", "B", 9, 9, "ヒューマン", "植田佳奈", "サレンディア救護院", 6, 0, 40, 12, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 121301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (120, "ミサキ（ステージ）", "ちょっとおませな恋に恋する女の子", "ファッション誌鑑賞、コスメ集め", "A", 3, 14, "魔族", "久野美咲", "ルーセント学院", 1, 0, 22, 11, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 121401);
