INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (159, "アンナ（パイレーツ）", "前世を信じる中二病患者、「疾風の冥姫」", "小説執筆", "A", 5, 13, "魔族", "髙野麻美", "トワイライトキャラバン", 7, 0, 45, 17, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 121901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (157, "シノブ（パイレーツ）", "占いが得意な霊能少女", "占い", "AB", 22, 7, "魔族", "大坪由佳", "悪魔偽王国軍（ディアボロス）", 12, 0, 42, 18, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 122001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (158, "アオイ（キャンプ）", "「友達」に憧れる、エルフの森の女の子", "友達作りのイメトレ", "AB", 6, 6, "エルフ", "花澤香菜", "フォレスティエ", 6, 0, 44, 13, "", 122101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (164, "ユカリ（キャンプ）", "純情でほっとけない大人の女性", "ウインドーショッピング", "A", 16, 12, "エルフ", "今井麻美", "メルクリウス財団", 3, 0, 55, 22, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 122201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (149, "ヴァンピィ", "けんぞくのご主人様", "お散歩、お料理", "AB", 6, "", "魔族", "釘宮理恵", "？？？", 12, 0, 41, "??", "", 122301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (155, "ヒヨリ（サマー）", "人助けが大好き！　前向き格闘娘", "人助け、応援", "A", 27, 2, "獣人族", "東山奈央", "トゥインクルウィッシュ", 8, 0, 44, 16, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 122401);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (163, "レイ（サマー）", "クールで何事にも真っ直ぐな剣士", "読書、乗馬、お茶", "B", 12, 2, "魔族", "早見沙織", "トゥインクルウィッシュ", 1, 0, 46, 18, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 122501);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (158, "ユイ（サマー）", "戦闘のサポートが得意な、心優しい少女", "料理、人間観察", "O", 5, 2, "ヒューマン", "種田梨沙", "トゥインクルウィッシュ", 4, 0, 47, 17, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 122601);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (118, "キョウカ（サマー）", "礼儀正しくしっかり者のちびっ子優等生", "お勉強", "A", 2, 5, "エルフ", "小倉唯", "リトルリリカル", 2, 0, 21, 8, "", 122701);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (128, "ミソギ（サマー）", "探検好きのイタズラっ子", "いたずら、探検", "O", 10, 5, "ヒューマン", "諸星すみれ", "リトルリリカル", 8, 0, 27, 9, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 122801);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117, "ミミ（サマー）", "お歌もにんじんも、ウサギさんも大好き♪", "かわいいもの集め", "O", 3, 5, "獣人族", "日高里菜", "リトルリリカル", 4, 0, 21, 10, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 122901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (150, "アメス", "新たな姿で騎士の冒険を支え続ける妖精", "？？？", "?", "?", "", "？？？", "相坂優歌", "？？？", "?", 0, "???", "??", "", 123001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (155, "マホ（エクスプローラー）", "マホマホ王国のプリンセス", "空想、ぬいぐるみ集め", "O", 22, 10, "獣人族", "内田真礼", "自警団（カォン）", 9, 0, 42, 16, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 123101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (148, "アヤネ（エクスプローラー）", "ぷうきちといつも一緒！", "屋内でできる遊び", "B", 10, 9, "ヒューマン", "芹澤優", "サレンディア救護院", 5, 0, 38, 14, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 123201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (157, "ネア", "ショタ大好き♪　ギャル系スライム娘", "可愛いショタと遊ぶ、買い物", "B", 13, 19, "魔族？", "和氣あず未", "レイジ・レギオン", 6, 0, 55, 19, "", 123301);
