INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (150, "ヨリ（クリスマス）", "人見知りであまのじゃくな女の子", "ゲーム全般", "O", 22, 7, "魔族", "原紗友里", "悪魔偽王国軍（ディアボロス）", 11, 0, 40, 13, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 124101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (171, "ジュン（クリスマス）", "素顔を見せない冷静沈着な女性騎士", "格闘技、湯浴み", "A", 25, 8, "ヒューマン", "川澄綾子", "王宮騎士団（NIGHTMARE）", 10, 0, 50, 25, "", 124201);
