INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (166, "ミツキ（ニューイヤー）", "実験が趣味の危険な科学者", "研究、実験", "A", 7, 13, "ヒューマン", "三石琴乃", "トワイライトキャラバン", 3, 0, 53, 27, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 124701);
