INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (148, "ムイミ（リベレイター）", "さまよえる謎の少女", "冒険、思い出話", "O", 11, "", "ヒューマン", "潘めぐみ", "？？？", 8, 0, 40, 16, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", 125001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (158, "タマキ（カフェ）", "弱きを助け強きをくじく猫娘", "猫とたわむれること", "AB", 1, 12, "獣人族", "沼倉愛美", "メルクリウス財団", 3, 0, 48, 19, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 125101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (140, "モニカ（カフェ）", "見た目も中身もお子ちゃまな異国の軍人", "お菓子屋通い", "A", 28, 15, "ヒューマン", "辻あゆみ", "ヴァイスフリューゲル　ランドソル支部", 7, 0, 33, 17, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 125201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (140, "コッコロ（レンジャー）", "主を慕う、小さなガイド役", "瞑想、動植物の飼育", "B", 11, 1, "エルフ", "伊藤美来", "美食殿", 5, 0, 35, 11, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 125301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (153, "シオリ（レンジャー）", "読書が趣味の病弱少女", "読書、お散歩", "A", 3, 11, "獣人族", "小清水亜美", "牧場（エリザベスパーク）", 11, 0, 40, 14, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 125401);
