INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (165, "ランファ（サマー）", "静寂を求め歌う陰気少女", "歌、読書、詩を書くこと", "O", 28, 19, "魔族", "原田彩楓", "レイジ・レギオン", 12, 0, 53, 20, "", 126901);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (157, "クウカ（サマー）", "妄想大好き！　ほんとは照れ屋な女の子", "小説を読むこと", "AB", 19, 15, "ヒューマン", "長妻樹里", "ヴァイスフリューゲル　ランドソル支部", 11, 0, 49, 18, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 127001);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (157, "シノブ（サマー）", "占いが得意な霊能少女", "占い", "AB", 22, 7, "魔族", "大坪由佳", "悪魔偽王国軍（ディアボロス）", 12, 0, 42, 18, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 127101);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (152, "キャル（編入生）", "行き倒れの謎のネコミミ魔法使い", "猫と遊ぶ", "A", 2, 1, "獣人族", "立花理香", "美食殿", 9, 0, 39, 14, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 127201);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (167, "スズナ（編入生）", "天真爛漫で人気者のカリスマモデル", "ファッション", "O", 10, 14, "魔族", "上坂すみれ", "ルーセント学院", 4, 0, 48, 17, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 127301);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (156, "サレン（サラサリア）", "救護院を経営する優しい庶民派お嬢様", "経営、お茶会", "A", 4, 9, "エルフ", "堀江由衣", "サレンディア救護院", 10, 0, 43, 17, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 127501);
