INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (158, "ユイ（アストラル）", "戦闘のサポートが得意な、心優しい少女", "料理、人間観察", "O", 5, 2, "ヒューマン", "種田梨沙", "トゥインクルウィッシュ", 4, 0, 47, 17, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 128901);
